tools.writeFile:
Writes content to a file in the workspace. First line of your argument must be the file path, remaining lines are the file content. Example:
src/utils.mjs
export function foo() { return 42; }

workspace.src/createUser.mjs:
export function createUser(name, email, age) {
  return {
    id: Math.random().toString(36).slice(2, 10),
    name,
    email,
    age,
    createdAt: new Date().toISOString()
  };
}

workspace.tests/createUser.test.mjs:
import { createUser } from '../src/createUser.mjs';

const assert = (c, m) => { if (!c) throw new Error(m); };

// Test 1: valid user is created correctly
const user = createUser('Alice', 'alice@example.com', 30);
assert(typeof user.id === 'string' && user.id.length > 0, 'User should have a non-empty id');
assert(user.name === 'Alice', 'Name should be Alice');
assert(user.email === 'alice@example.com', 'Email should match');
assert(user.age === 30, 'Age should be 30');
assert(typeof user.createdAt === 'string', 'Should have createdAt timestamp');

// Test 2: empty name throws
try {
  createUser('', 'a@b.com', 25);
  assert(false, 'Should throw for empty name');
} catch (e) {
  assert(e.message.toLowerCase().includes('name'), 'Error should mention name: ' + e.message);
}

// Test 3: non-string name throws
try {
  createUser(123, 'a@b.com', 25);
  assert(false, 'Should throw for non-string name');
} catch (e) {
  assert(e.message.toLowerCase().includes('name'), 'Error should mention name: ' + e.message);
}

// Test 4: invalid email (no @) throws
try {
  createUser('Bob', 'invalid-email', 25);
  assert(false, 'Should throw for invalid email');
} catch (e) {
  assert(e.message.toLowerCase().includes('email'), 'Error should mention email: ' + e.message);
}

// Test 5: age out of range throws
try {
  createUser('Bob', 'bob@example.com', -1);
  assert(false, 'Should throw for negative age');
} catch (e) {
  assert(e.message.toLowerCase().includes('age'), 'Error should mention age: ' + e.message);
}

try {
  createUser('Bob', 'bob@example.com', 151);
  assert(false, 'Should throw for age > 150');
} catch (e) {
  assert(e.message.toLowerCase().includes('age'), 'Error should mention age: ' + e.message);
}

// Test 6: non-number age throws
try {
  createUser('Bob', 'bob@example.com', 'thirty');
  assert(false, 'Should throw for non-number age');
} catch (e) {
  assert(e.message.toLowerCase().includes('age'), 'Error should mention age: ' + e.message);
}

console.log('ALL TESTS PASSED');
